        if (key == null || key.isEmpty()) {
            throw new IllegalArgumentException("Encryption key must not be null or empty");
        }
        if (data == null) {
            throw new IllegalArgumentException("Data to encrypt must not be null");
        }

        try {
            // Create the secret key specification from the key string bytes
            byte[] keyBytes = key.getBytes(StandardCharsets.UTF_8);
            SecretKeySpec secretKeySpec = new SecretKeySpec(keyBytes, ALGORITHM);

            // Initialize the cipher in encryption mode
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, secretKeySpec);

            // Perform the encryption
            byte[] encryptedBytes = cipher.doFinal(data);

            // Convert the encrypted bytes to a hexadecimal string
            return bytesToHex(encryptedBytes);
        } catch (Exception e) {
            // Log the exception details (avoid exposing sensitive info)
            throw new RuntimeException("AES encryption failed", e);
        }
    }

    /**
     * Converts a byte array to its lowercase hexadecimal string representation.
     *
     * @param bytes the byte array to convert
     * @return the hexadecimal string representation
     */
    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder(bytes.length * 2);
        for (byte b : bytes) {
            sb.append(HEX_CHARS[(b >> 4) & 0x0F]);
            sb.append(HEX_CHARS[b & 0x0F]);
        }
        return sb.toString();
    }
}
